/* ═══════════════════════════════════════════════════════════════
 *  MAIN APP
 * ═══════════════════════════════════════════════════════════════ */
export default function TeamStatsPage() {
  const [activeTab, setActiveTab] = useState("Overview");
  const scrollRef = useRef(null);
  const [scrollY, setScrollY] = useState(0);

  const handleScroll = useCallback(() => {
    if (scrollRef.current) setScrollY(scrollRef.current.scrollTop);
  }, []);

  useEffect(() => {
    const el = scrollRef.current;
    if (el) el.addEventListener("scroll", handleScroll, { passive: true });
    return () => el && el.removeEventListener("scroll", handleScroll);
  }, [handleScroll]);

  const COLLAPSE_START = 0;
  const COLLAPSE_END = 100;
  const progress = Math.min(1, Math.max(0, (scrollY - COLLAPSE_START) / (COLLAPSE_END - COLLAPSE_START)));
  const headerHeight = 106 * (1 - progress);

  const last10Wins = last10Games.filter((g) => g.result === "W").length;

  return (
    <div style={{
      width: "100%", maxWidth: 393, margin: "0 auto", height: "100vh", overflow: "hidden",
      fontFamily: "'Inter', sans-serif", position: "relative", background: pageBg,
    }}>
      {/* ─── Status Bar ─── */}
      <div style={{
        height: 62, flexShrink: 0,
        display: "flex", alignItems: "flex-end", justifyContent: "space-between",
        padding: `0 24px 19px`,
        background: "rgba(255,255,255,0.4)",
      }}>
        <span style={{ fontFamily: "'SF Pro Text', 'SF Pro', -apple-system, system-ui, sans-serif", fontSize: 17, fontWeight: t.semibold, color: "#090909", lineHeight: "22px" }}>9:41</span>
        <StatusBarIcons />
      </div>

      {/* ─── Top Navigation ─── */}
      <div style={{
        display: "flex", alignItems: "center", padding: `${t.lg}px`,
        flexShrink: 0,
        background: "linear-gradient(to bottom, rgba(255,255,255,0.4) 95.455%, rgba(153,153,153,0) 108.52%)",
      }}>
        <div style={{ width: 24, cursor: "pointer" }}><IconBackArrow /></div>
        <div style={{ flex: 1, textAlign: "center" }}>
          <span style={{ ...font(24, t.semibold, { lineHeight: t.heading2 }), color: t.primary }}>Charlotte Hornets</span>
        </div>
        <div style={{ width: 24, cursor: "pointer" }}><IconShare /></div>
      </div>

      {/* ─── Scrollable content ─── */}
      <div
        ref={scrollRef}
        style={{
          flex: 1, overflowY: "auto", WebkitOverflowScrolling: "touch",
          height: `calc(100vh - 135px)`,
        }}
      >
        {/* ─── Team header — collapses on scroll ─── */}
        <div data-capture="team-header" style={{
          overflow: "visible",
          height: headerHeight,
          willChange: "height",
          position: "relative",
          WebkitMaskImage: progress > 0
            ? `linear-gradient(to bottom, black ${Math.max(0, (1 - progress * 1.5)) * 100}%, transparent 100%)`
            : "none",
          maskImage: progress > 0
            ? `linear-gradient(to bottom, black ${Math.max(0, (1 - progress * 1.5)) * 100}%, transparent 100%)`
            : "none",
        }}>
          {/* Gradient background — extends below header and fades out */}
          <div style={{
            position: "absolute", top: -1, left: 0, right: 0, bottom: -40,
            zIndex: 0,
            background: "linear-gradient(135deg, rgba(22,131,149,0.45) 0%, rgba(22,131,149,0.25) 30%, #cdd9dc 50%, rgba(29,17,96,0.14) 70%, rgba(29,17,96,0.25) 100%)",
            WebkitMaskImage: "linear-gradient(to bottom, black 0%, black 75%, transparent 100%)",
            maskImage: "linear-gradient(to bottom, black 0%, black 75%, transparent 100%)",
          }} />
          <div style={{
            height: 106,
            display: "flex", alignItems: "center",
            padding: `0 ${t.md}px`,
            gap: t.md, width: "100%", boxSizing: "border-box",
            position: "relative",
          }}>
            {/* Team logo — team-color tinted watermark */}
            <div style={{
              position: "relative", width: 175, flexShrink: 0, zIndex: 0, marginLeft: -20,
              opacity: 0.42,
              WebkitMaskImage: "radial-gradient(ellipse 90% 80% at 40% 40%, black 10%, transparent 65%)",
              maskImage: "radial-gradient(ellipse 90% 80% at 40% 40%, black 10%, transparent 65%)",
            }}>
              <img
                src={team.logo}
                alt={team.name}
                style={{
                  width: "100%",
                  objectFit: "contain",
                  display: "block",
                }}
              />
              {/* Team color overlay — multiplies with logo */}
              <div style={{
                position: "absolute", inset: 0,
                background: teamHex,
                mixBlendMode: "multiply",
                opacity: 0.6,
              }} />
            </div>
            {/* Team info */}
            <div style={{ flex: 1, display: "flex", flexDirection: "column", gap: t.xs, justifyContent: "center", height: "100%", zIndex: 1 }}>
              <div style={{ display: "flex", gap: t.sm, alignItems: "center" }}>
                <span style={{ ...font(13, t.regular), color: t.secondary }}>Record</span>
                <span style={{ ...font(13, t.medium), color: t.primary }}>{team.record}</span>
              </div>
              <div style={{ display: "flex", gap: t.sm, alignItems: "center" }}>
                <span style={{ ...font(13, t.regular), color: t.secondary }}>Home</span>
                <span style={{ ...font(13, t.medium), color: t.primary }}>17-12</span>
                <span style={{ ...font(13, t.regular), color: t.textTertiary }}>·</span>
                <span style={{ ...font(13, t.regular), color: t.secondary }}>Away</span>
                <span style={{ ...font(13, t.medium), color: t.primary }}>13-19</span>
              </div>
              <div style={{ display: "flex", gap: t.sm, alignItems: "center" }}>
                <span style={{ ...font(13, t.regular), color: t.secondary }}>Last 10</span>
                <span style={{ ...font(13, t.medium), color: t.primary }}>{last10Wins}-{10 - last10Wins}</span>
                <span style={{ ...font(13, t.regular), color: t.textTertiary }}>·</span>
                <span style={{ ...font(13, t.medium), color: t.accentGreen }}>W4</span>
              </div>
            </div>
          </div>
        </div>

        {/* ─── Segmented control — sticky ─── */}
        <div style={{
          position: "sticky", top: 0, zIndex: 10,
          padding: `${t.lg}px`,
          background: progress > 0.1 ? pageBg : "transparent",
          WebkitMaskImage: progress > 0.1
            ? "linear-gradient(to bottom, black 70%, transparent 100%)" : "none",
          maskImage: progress > 0.1
            ? "linear-gradient(to bottom, black 70%, transparent 100%)" : "none",
          paddingBottom: progress > 0.1 ? t.lg + 24 : t.lg,
          transition: "padding-bottom 0.2s",
        }}>
          <PillControl
            tabs={["Overview", "Roster", "Schedule"]}
            activeTab={activeTab}
            onTabChange={setActiveTab}
            accentColor={teamColorSolid}
            style={{ width: "100%" }}
          />
        </div>

        {/* ─── Content cards ─── */}
        <div style={{
          display: "flex", flexDirection: "column", gap: t.lg,
          padding: `0 ${t.lg}px ${t.lg * 3}px`,
        }}>
          {activeTab === "Overview" && <OverviewTab />}
          {activeTab === "Roster" && <RosterTab />}
          {activeTab === "Schedule" && <ScheduleTab />}
        </div>
      </div>

      {/* ─── Home Indicator ─── */}
      <div style={{
        position: "absolute", bottom: 4, left: "50%", transform: "translateX(-50%)",
        width: 144, height: 5, borderRadius: 100, background: "rgba(128,128,128,0.55)",
      }} />
    </div>
  );
}
